use hex_literal::hex;
use near_sdk::{test_utils::VMContextBuilder, testing_env};

use redstone_adapter::*;

#[test]
fn test() {
    let context = VMContextBuilder::new()
        .block_timestamp(1770985144000 * 1_000_000)
        .build();
    testing_env!(context.clone());

    let mut ra = RedStoneAdapter::new();

    let prices = vec!["ETH".to_string(), "BTC".to_string()];

    let input = hex!("");

    ra.write_prices(prices.clone(), input.to_vec().into());

    let price_data = ra.read_price_data(prices.clone());

    eprintln!("{price_data:#?}");
}
